data.content:
**MSTest does not have `Assert.IsGreaterThan` or `Assert.IsInRange`.** Those don't exist. Here's what MSTest actually provides for comparisons:

| Need | MSTest Approach |
|---|---|
| Exact value | `Assert.AreEqual(expected, actual)` |
| Comparison | `Assert.IsTrue(actual > threshold)` ¹ |
| Exception | `Assert.ThrowsException<T>(action)` |

¹ `Assert.IsTrue` gives poor failure messages (just "expected True, got False"). For richer output, use the overload with a message string, or consider the **FluentAssertions** NuGet package which provides `.Should().BeGreaterThan()`, `.BeInRange()`, etc.

Here's a test class using what MSTest actually offers:

```csharp
using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    // ── CalculatePercentage ──────────────────────────────

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 5, 0.0)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(
        int correct, int total, double expected)
    {
        Assert.AreEqual(expected, _calc.CalculatePercentage(correct, total), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_TotalZero_Throws()
        => Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
        => Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
        => Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));

    // ── GetGrade ─────────────────────────────────────────

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.9, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.9, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.9, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    [DataRow(0.0, "F")]
    public void GetGrade_BoundaryValues_ReturnsCorrectGrade(
        double percentage, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(percentage));
    }

    // ── NormalizeScore ───────────────────────────────────

    [TestMethod]
    public void NormalizeScore_HalfOfMax_Returns50()
        => Assert.AreEqual(50.0, _calc.NormalizeScore(25, 50), 0.001);

    [TestMethod]
    public void NormalizeScore_ExceedsMax_ClampedTo100()
    {
        double result = _calc.NormalizeScore(120, 100);
        Assert.AreEqual(100.0, result, 0.001);
        // Compare manually — no Assert.IsLessThanOrEqual exists:
        Assert.IsTrue(result <= 100.0, $"Expected ≤ 100 but got {result}");
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
        => Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(-1, 100));

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
        => Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(50, 0));
}
```

**Key takeaways:**
- Use `Assert.AreEqual(expected, actual, delta)` for floating-point comparisons (the third arg is tolerance)
- Use `Assert.IsTrue(condition, message)` with a descriptive message string for range/comparison checks — the message is critical for debuggability
- Use `[DataRow]` to test boundary values systematically (note the 89.9/79.9 etc. boundary pairs above)
